def get_target_for_redirect(target: str, domain: str) -> str:
    from urllib.parse import urlparse

    parsed = urlparse(target)
    hostname = parsed.hostname or ''

    # Check if hostname equals domain or is a subdomain of domain
    if hostname == domain or hostname.endswith('.' + domain):
        # Return target with https protocol
        if parsed.scheme == 'https':
            return target
        else:
            # Replace scheme with https
            return parsed._replace(scheme='https').geturl()
    else:
        return 'https://' + domain

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Resolve the directory path to an absolute path
        abs_dir_path = os.path.realpath(dir_path)

        # Construct the full file path
        full_path = os.path.realpath(os.path.join(abs_dir_path, filename))

        # Security check: ensure the resolved path is within the directory
        if not full_path.startswith(abs_dir_path + os.sep) and full_path != abs_dir_path:
            return ""

        with open(full_path, 'r') as f:
            return f.read()
    except Exception:
        return ""

