from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data.encode() if isinstance(xml_data, str) else xml_data)

    # Use parameterized XPath to avoid XPath injection
    students = root.xpath(
        "student[username=$uname and password=$pwd]",
        uname=username,
        pwd=password
    )

    if not students:
        return None

    student = students[0]
    result = {}
    for child in student:
        result[child.tag] = child.text if child.text is not None else ""

    return result

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id or not user_id.strip():
        return None

    if not user_id.isalnum():
        return None

    return f"{api_url}/{user_id}"

