import subprocess

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    ALLOWED_COMMANDS = {'ls', 'pwd', 'whoami', 'date', 'echo', 'cat', 'uname'}

    command = input("Enter command: ").strip()

    if not command:
        print("No command provided.")
        return

    parts = command.split()
    base_command = parts[0]

    if base_command not in ALLOWED_COMMANDS:
        print(f"Command '{base_command}' is not allowed.")
        return

    # Validate arguments - reject any that look like shell injection
    for arg in parts[1:]:
        if any(char in arg for char in [';', '&', '|', '`', '$', '>', '<', '!', '\n', '\r']):
            print("Invalid characters in arguments.")
            return

    try:
        result = subprocess.run(parts, capture_output=True, text=True, timeout=10, shell=False)
        print(result.stdout)
        if result.stderr:
            print(result.stderr)
    except subprocess.TimeoutExpired:
        print("Command timed out.")
    except FileNotFoundError:
        print(f"Command '{base_command}' not found.")
    except Exception as e:
        print(f"Error executing command: {e}")

